INSERT INTO `assignments` VALUES (1,'2026-01-01 12:18:49.986674','2026-01-01 12:18:49.986720',2,'Một hệ thống Quản lý Sinh viên cho phép:\nThêm mới sinh viên\nXem danh sách sinh viên\nXem chi tiết sinh viên\nCập nhật thông tin sinh viên\nXóa sinh viên khỏi hệ thống\nHệ thống được xây dựng theo mô hình Client – Server, trong đó Back-End cung cấp các API để Front-End sử dụng.\nPhần 1: Phân tích dữ liệu (2 điểm)\nMô tả đối tượng Student với các thuộc tính:\nid\nfullName\nemail\ndateOfBirth\nmajor\nYêu cầu:\nGiải thích ngắn gọn ý nghĩa của từng thuộc tính\nChỉ ra kiểu dữ liệu phù hợp cho mỗi thuộc tính\nPhần 2: Thiết kế API (4 điểm)\nThiết kế các API cho hệ thống theo chuẩn RESTful.\nVới mỗi API, trình bày:\nHTTP Method\nURL\nMô tả chức năng\nDữ liệu request (nếu có)\nDữ liệu response (dạng JSON mẫu)\nVí dụ:\nLấy danh sách sinh viên\nThêm mới sinh viên\nCập nhật sinh viên\nXóa sinh viên\nPhần 3: Luồng xử lý Back-End (2 điểm)\nMô tả bằng lời (hoặc sơ đồ) luồng xử lý khi:\nClient gửi request tạo mới sinh viên\nGợi ý:\nClient gửi HTTP request\nController nhận request\nKiểm tra dữ liệu đầu vào\nGọi Service xử lý nghiệp vụ\nLưu dữ liệu vào Database\nTrả response về Client\nPhần 4: Xử lý lỗi & Validation (1 điểm)\nTrình bày cách Back-End xử lý các trường hợp:\nEmail không đúng định dạng\nThiếu thông tin bắt buộc\nKhông tìm thấy sinh viên theo ID\nPhần 5: Kiến thức nền tảng (1 điểm)\nTrả lời ngắn gọn:\nRESTful API là gì?\nSự khác nhau giữa GET và POST\nVì sao Back-End thường trả dữ liệu dưới dạng JSON?\n4. Yêu cầu trình bày\nNộp 01 file PDF\nTối đa 10 trang A4\nCó trang bìa (tên sinh viên, MSSV, môn học)\nTrình bày rõ ràng, có tiêu đề từng phần',8,'2026-01-01 17:00:00.000000',_binary '\0',10,_binary '','PHÂN TÍCH VÀ THIẾT KẾ HỆ THỐNG BACK-END CƠ BẢN'),(2,'2026-01-07 09:13:11.848451','2026-01-07 09:13:11.848537',8,'Clone 1 mini project từ link đính kèm\nTạo file GitReadme.md\nViết chức năng của các câu lệnh git đã nêu ở mô tả\nCommit và push code lên Repo',10,'2026-01-10 17:00:00.000000',_binary '\0',10,_binary '','Các câu lệnh cơ bản với Git'),(3,'2026-01-07 09:14:26.174229','2026-01-07 09:14:26.174293',2,'Thực hiện xây dựng giao diện 1 màn danh sách user',9,'2026-01-16 17:00:00.000000',_binary '\0',10,_binary '','Bài tập tuần 2'),(4,'2026-01-07 09:15:03.820503','2026-01-07 09:15:03.820523',8,'Tạo 1 mini project: (bất cứ đề tài gì)\nSử dụng các lệnh git đã học để kết nối tới repo\nĐẩy project lên Github',10,'2026-01-11 17:00:00.000000',_binary '\0',10,_binary '\0','Tạo và quản lý Repo với Github'),(5,'2026-01-07 11:23:57.993793','2026-01-07 11:23:57.993855',9,'Tạo một thư mục dự án mới, khởi tạo Git repository, tạo file README.md với thông tin cá nhân (họ tên, mã sinh viên, lớp), thực hiện add và commit với message phù hợp. Chụp ảnh màn hình kết quả lệnh git log.',11,'2026-01-07 17:00:00.000000',_binary '\0',10,_binary '','Khởi tạo repository và commit đầu tiên'),(6,'2026-01-07 11:26:57.315512','2026-01-07 11:26:57.315547',9,'Tạo một dự án website đơn giản gồm 3 file: index.html, style.css, script.js. Thực hiện ít nhất 5 commit với các thay đổi khác nhau. Sử dụng git status, git diff, git log --oneline để theo dõi lịch sử. Tạo file .gitignore để loại bỏ các file không cần thiết.',11,'2026-01-09 17:00:00.000000',_binary '\0',10,_binary '','Thực hành các lệnh Git cơ bản'),(7,'2026-01-07 11:27:40.444488','2026-01-07 11:27:40.444529',9,'Từ dự án ở bài tập 2, tạo branch mới tên \'feature/login\' để phát triển tính năng đăng nhập. Thực hiện ít nhất 3 commit trên branch mới. Sau đó checkout về branch main và merge branch feature/login vào main. Chụp ảnh minh họa quá trình.',11,'2026-01-14 17:00:00.000000',_binary '\0',10,_binary '','Làm việc với Branch'),(8,'2026-01-07 12:21:41.951582','2026-01-07 12:24:25.509782',11,'Tạo một lớp Calculator với các phương thức: \nadd (cộng hai số), subtract (trừ hai số), multiply (nhân hai số), divide (chia hai số, throw ArithmeticException nếu chia cho 0), isEven (kiểm tra số chẵn), factorial (tính giai thừa, throw IllegalArgumentException nếu n âm). \nSau đó tạo lớp CalculatorTest để viết unit test cho tất cả các phương thức trên. Yêu cầu test các trường hợp số dương, số âm, số 0, các trường hợp exception. Sử dụng @ParameterizedTest để test nhiều bộ dữ liệu, sử dụng @BeforeEach và @AfterEach hợp lý. Viết báo cáo PDF bao gồm mô tả các test case, giải thích lý do chọn test case, screenshot kết quả chạy test và code coverage (yêu cầu >= 80%). Nộp file source code nén (.zip) và báo cáo (.pdf), đặt tên file theo định dạng MaSV_HoTen_BT1.',11,'2026-01-08 13:00:00.000000',_binary '\0',10,_binary '','Viết Unit Test cơ bản với JUnit 5'),(9,'2026-01-07 12:25:58.594749','2026-01-07 12:25:58.594826',11,'Xây dựng hệ thống quản lý đơn hàng đơn giản gồm: Interface OrderRepository với các phương thức findById, findAll, save, deleteById. Interface EmailService với các phương thức sendOrderConfirmation và sendOrderCancellation. Class OrderService inject OrderRepository và EmailService, có các phương thức createOrder (lưu order và gửi email xác nhận), cancelOrder (xóa order và gửi email hủy), getOrderById, calculateTotalRevenue. \nTạo lớp OrderServiceTest sử dụng @Mock để mock OrderRepository và EmailService, @InjectMocks cho OrderService. \nTest các trường hợp tạo đơn hàng thành công và thất bại, hủy đơn hàng tồn tại và không tồn tại, tính tổng doanh thu. \nSử dụng verify() để kiểm tra method được gọi đúng, ArgumentCaptor để kiểm tra tham số. Viết báo cáo PDF giải thích tại sao cần mock dependency, mô tả test case, screenshot kết quả và so sánh @Mock vs @Spy. \nNộp file source code nén (.zip) và báo cáo (.pdf), đặt tên file theo định dạng MaSV_HoTen_BT2.',11,'2026-01-14 17:00:00.000000',_binary '\0',10,_binary '','Mocking Dependencies với Mockito'),(10,'2026-01-07 12:27:28.915613','2026-01-07 12:27:28.915658',11,'Tạo ứng dụng Spring Boot quản lý sinh viên gồm Entity Student (id, name, email, gpa), Repository StudentRepository extends JpaRepository với custom method findByEmailContaining và findByGpaGreaterThan, Service StudentService có CRUD operations và getHonorStudents (GPA >= 3.5), Controller StudentController với REST endpoints. Viết Repository Test sử dụng @DataJpaTest với H2 database để test custom query. Viết Service Test sử dụng @ExtendWith(MockitoExtension.class) để mock repository và test business logic. Viết Controller Test sử dụng @WebMvcTest với MockMvc để test các endpoint GET, POST, PUT, DELETE. Viết Integration Test sử dụng @SpringBootTest để test end-to-end flow. Viết báo cáo PDF tối thiểu 5 trang bao gồm kiến trúc ứng dụng, giải thích sự khác nhau giữa các annotation test, bảng tổng hợp test cases, screenshot code coverage (>= 70%), kết luận. \nQuay video demo chạy test upload lên YouTube hoặc Drive. Nộp file source code nén (.zip) và báo cáo (.pdf), đặt tên file theo định dạng MaSV_HoTen_BT3.',11,'2026-01-25 03:00:00.000000',_binary '\0',10,_binary '','Testing ứng dụng Spring Boot');
