DROP TABLE IF EXISTS `exam_question_snapshot`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `exam_question_snapshot` (
  `id` bigint NOT NULL AUTO_INCREMENT,
  `created_at` datetime(6) NOT NULL,
  `updated_at` datetime(6) NOT NULL,
  `difficulty_level` int NOT NULL,
  `exam_id` bigint NOT NULL,
  `order_index` int DEFAULT NULL,
  `question_content` text NOT NULL,
  `question_image_url` varchar(255) DEFAULT NULL,
  `question_type` enum('MULTI_CHOICE','SINGLE_CHOICE') NOT NULL,
  `score` double DEFAULT NULL,
  `session_exam_id` bigint DEFAULT NULL,
  `source_question_id` bigint NOT NULL,
  `topic_id` bigint DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `FKp7l0l6g74oe6ug69xmfainr8y` (`exam_id`),
  KEY `FKiuhtq01tu80errbpdrj6xa33d` (`session_exam_id`),
  CONSTRAINT `FKiuhtq01tu80errbpdrj6xa33d` FOREIGN KEY (`session_exam_id`) REFERENCES `session_exams` (`session_exam_id`),
  CONSTRAINT `FKp7l0l6g74oe6ug69xmfainr8y` FOREIGN KEY (`exam_id`) REFERENCES `exams` (`exam_id`)
) ENGINE=InnoDB AUTO_INCREMENT=221 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;
