INSERT INTO `exams` VALUES (1,'2025-12-26 22:51:28.660200','2025-12-26 22:51:28.660236',8,'Kiểm tra khái niệm cơ bản: Class vs Object, thuộc tính và phương thức. Đọc hiểu sơ đồ lớp (Class Diagram) và mối quan hệ giữa các đối tượng.',_binary '\0',4,'Tư duy Hướng đối tượng & UML'),(2,'2025-12-26 22:51:55.345534','2025-12-26 22:51:55.345544',8,'Kiểm tra kiến thức về các thẻ ngữ nghĩa (header, footer, section...), độ ưu tiên trong CSS (Specificity), Box Model và các thuộc tính Flexbox/Grid cơ bản.',_binary '\0',6,'HTML5 Semantic & CSS3 Layout'),(3,'2025-12-26 22:52:11.875513','2025-12-26 22:52:11.875523',8,'Tập trung vào logic JS: Kiểu dữ liệu, cơ chế Hoisting, Scope (var/let/const), Arrow Function, Callback và các phương thức xử lý Mảng (Map, Filter, Reduce).',_binary '\0',6,'JavaScript Core: Biến & Hàm'),(4,'2025-12-26 22:52:25.309386','2025-12-26 22:52:25.309394',8,'Lý thuyết về DOM Tree. Cách chọn phần tử (querySelector), thêm/xóa class, và cơ chế Event Bubbling/Capturing trong xử lý sự kiện click/input',_binary '\0',6,'DOM Manipulation & Sự kiện'),(5,'2025-12-26 22:52:43.716464','2025-12-26 22:52:43.716471',8,'Kiểm tra kiến thức về vòng đời Request-Response. Ý nghĩa các HTTP Methods (GET, POST, PUT, DELETE) và HTTP Status Codes (200, 201, 400, 401, 404, 500).',_binary '\0',8,'Tổng quan HTTP & Client-Server'),(6,'2025-12-26 22:52:56.527668','2025-12-26 22:52:56.527674',8,'Các quy tắc đặt tên Endpoint chuẩn REST. Cách cấu trúc dữ liệu trả về (JSON Response). Phân biệt Query Parameters và Path Variables.',_binary '\0',8,'Nguyên lý thiết kế RESTful API'),(7,'2025-12-26 22:53:10.005767','2025-12-26 22:53:10.005778',8,'Kiến thức về kết nối CSDL, khái niệm ORM. Các lỗ hổng bảo mật cơ bản (SQL Injection) và cơ chế xác thực người dùng (Authentication vs Authorization).',_binary '\0',8,'Database & Bảo mật cơ bản'),(8,'2025-12-27 18:08:54.493049','2025-12-27 18:09:20.907160',8,'123',_binary '',8,'test'),(9,'2025-12-27 20:17:05.590679','2025-12-27 20:17:05.590770',11,'Kiểm tra oop',_binary '\0',4,'Kiểm tra 15 phút'),(10,'2025-12-28 01:31:43.454074','2026-01-07 14:16:05.107996',9,'Thi thử cho môn học lần 1',_binary '',8,'Thi thử lần 1'),(11,'2025-12-28 01:36:08.486293','2026-01-07 14:16:19.804238',9,'Thi thử cho môn DSA',_binary '',5,'Thi thử lần 1'),(12,'2026-01-07 09:20:19.285375','2026-01-07 09:20:19.285391',10,'Kiểm tra Git vs GitHub',_binary '\0',7,'Git & github'),(13,'2026-01-07 12:52:22.250428','2026-01-07 12:52:22.250757',11,'Kiểm tra các khai niệm cơ bản của UT',_binary '\0',17,'Kiểm tra chương 1 UT'),(14,'2026-01-07 12:55:20.112090','2026-01-07 12:55:20.112108',11,'Kiểm tra kiến thức tổng hợp về Unit Test',_binary '\0',17,'Kiểm tra giữa kỳ'),(15,'2026-01-07 14:20:47.629865','2026-01-07 14:20:47.629905',9,'Kiểm tra 1h',_binary '\0',6,'Thi thử lần 1');
