INSERT INTO `questions` VALUES (1,'2025-12-26 22:15:03.757062','2025-12-26 22:15:03.757099','Trong OOP, Class là gì?',8,1,NULL,_binary '\0',_binary '\0',_binary '\0',1,'SINGLE_CHOICE'),(2,'2025-12-26 22:15:03.810666','2025-12-26 22:15:03.810692','Đặc điểm nào sau đây KHÔNG phải là đặc trưng của Đối tượng (Object)?',8,1,NULL,_binary '\0',_binary '\0',_binary '\0',1,'SINGLE_CHOICE'),(3,'2025-12-26 22:15:03.851635','2025-12-26 22:15:03.851655','Để tạo một Object từ Class trong nhiều ngôn ngữ lập trình, ta thường sử dụng từ khóa nào?',8,1,NULL,_binary '\0',_binary '\0',_binary '\0',1,'SINGLE_CHOICE'),(4,'2025-12-26 22:15:03.874762','2025-12-26 22:15:03.874781','Thuộc tính (Attribute) của một Đối tượng mô tả điều gì?',8,1,NULL,_binary '\0',_binary '\0',_binary '\0',1,'SINGLE_CHOICE'),(5,'2025-12-26 22:15:03.901238','2025-12-26 22:15:03.901255','Phương thức (Method) của một Đối tượng mô tả điều gì?',8,1,NULL,_binary '\0',_binary '\0',_binary '\0',1,'SINGLE_CHOICE'),(6,'2025-12-26 22:15:03.937798','2025-12-26 22:15:03.937822','Mục đích chính của Lập trình Hướng đối tượng (OOP) là gì?',8,1,NULL,_binary '\0',_binary '\0',_binary '\0',1,'SINGLE_CHOICE'),(7,'2025-12-26 22:15:03.979193','2025-12-26 22:15:03.979216','Một Class có thể tạo ra bao nhiêu Object?',8,1,NULL,_binary '\0',_binary '\0',_binary '\0',1,'SINGLE_CHOICE'),(8,'2025-12-26 22:15:04.011459','2025-12-26 22:15:04.011479','Khi một Object được tạo ra, điều gì sẽ xảy ra?',8,1,NULL,_binary '\0',_binary '\0',_binary '\0',1,'SINGLE_CHOICE'),(9,'2025-12-26 22:15:04.037856','2025-12-26 22:15:04.037898','Class thường được đặt tên theo quy tắc nào?',8,1,NULL,_binary '\0',_binary '\0',_binary '\0',1,'SINGLE_CHOICE'),(10,'2025-12-26 22:15:04.069783','2025-12-26 22:15:04.069808','Thuật ngữ nào sau đây đồng nghĩa với \"phiên bản\" (instance) của một Class?',8,1,NULL,_binary '\0',_binary '\0',_binary '\0',1,'SINGLE_CHOICE'),(11,'2025-12-26 22:15:04.099139','2025-12-26 22:15:04.099163','Sự khác biệt cơ bản giữa Class và Interface là gì?',8,2,NULL,_binary '\0',_binary '\0',_binary '\0',1,'SINGLE_CHOICE'),(12,'2025-12-26 22:15:04.133435','2025-12-26 22:15:04.133463','Từ khóa nào được sử dụng để tham chiếu đến Object hiện tại bên trong một Method?',8,2,NULL,_binary '\0',_binary '\0',_binary '\0',1,'SINGLE_CHOICE'),(13,'2025-12-26 22:15:04.171800','2025-12-26 22:15:04.171828','Khi nào thì nên sử dụng từ khóa `static` cho một thuộc tính hoặc phương thức?',8,2,NULL,_binary '\0',_binary '\0',_binary '\0',1,'SINGLE_CHOICE'),(14,'2025-12-26 22:15:04.200094','2025-12-26 22:15:04.200119','Phương thức `toString()` trong Java/C\\# dùng để làm gì?',8,2,NULL,_binary '\0',_binary '\0',_binary '\0',1,'SINGLE_CHOICE'),(15,'2025-12-26 22:15:04.228710','2025-12-26 22:15:04.228731','Trong thiết kế Class, nguyên tắc SOLID nào tập trung vào trách nhiệm đơn nhất của Class?',8,2,NULL,_binary '\0',_binary '\0',_binary '\0',1,'SINGLE_CHOICE'),(16,'2025-12-26 22:15:04.260013','2025-12-26 22:15:04.260033','Tại sao việc tách Class thành các file riêng biệt (ví dụ: trong Java, C#) lại quan trọng?',8,3,NULL,_binary '\0',_binary '\0',_binary '\0',1,'SINGLE_CHOICE'),(17,'2025-12-26 22:15:04.289573','2025-12-26 22:15:04.289593','Phân biệt giữa \"Aggregation\" và \"Composition\" trong mối quan hệ giữa các đối tượng.',8,3,NULL,_binary '\0',_binary '\0',_binary '\0',1,'SINGLE_CHOICE'),(18,'2025-12-26 22:15:04.315784','2025-12-26 22:15:04.315805','Giải thích ý nghĩa của `scope` (phạm vi truy cập) của các thành viên Class.',8,3,NULL,_binary '\0',_binary '\0',_binary '\0',1,'SINGLE_CHOICE'),(19,'2025-12-26 22:15:04.340949','2025-12-26 22:15:04.340971','Cho một Class đơn giản, tại sao việc tạo một Object quá lớn (với nhiều thuộc tính không cần thiết) lại là một bad practice?',8,3,NULL,_binary '\0',_binary '\0',_binary '\0',1,'SINGLE_CHOICE'),(20,'2025-12-26 22:15:04.369723','2025-12-26 22:15:04.369747','Trong một hệ thống đa luồng (multithreading), việc sử dụng các Object có trạng thái (stateful objects) có thể gây ra vấn đề gì?',8,3,NULL,_binary '\0',_binary '\0',_binary '\0',1,'SINGLE_CHOICE'),(21,'2025-12-26 22:15:04.390631','2025-12-26 22:15:04.390649','Tính đóng gói (Encapsulation) là gì trong OOP?',8,1,NULL,_binary '\0',_binary '\0',_binary '\0',2,'SINGLE_CHOICE'),(22,'2025-12-26 22:15:04.422789','2025-12-26 22:15:04.422819','Từ khóa nào thường được dùng để chỉ định một thuộc tính là Private (riêng tư)?',8,1,NULL,_binary '\0',_binary '\0',_binary '\0',2,'SINGLE_CHOICE'),(23,'2025-12-26 22:15:04.456516','2025-12-26 22:15:04.456541','Phương thức `Getter` có chức năng gì?',8,1,NULL,_binary '\0',_binary '\0',_binary '\0',2,'SINGLE_CHOICE'),(24,'2025-12-26 22:15:04.488161','2025-12-26 22:15:04.488184','Phương thức `Setter` có chức năng gì?',8,1,NULL,_binary '\0',_binary '\0',_binary '\0',2,'SINGLE_CHOICE'),(25,'2025-12-26 22:15:04.524706','2025-12-26 22:15:04.524732','Constructor là gì?',8,1,NULL,_binary '\0',_binary '\0',_binary '\0',2,'SINGLE_CHOICE'),(26,'2025-12-26 22:15:04.561658','2025-12-26 22:15:04.561678','Constructor KHÔNG có đặc điểm nào sau đây?',8,1,NULL,_binary '\0',_binary '\0',_binary '\0',2,'SINGLE_CHOICE'),(27,'2025-12-26 22:15:04.593277','2025-12-26 22:15:04.593301','Mục đích chính của việc sử dụng Constructor?',8,1,NULL,_binary '\0',_binary '\0',_binary '\0',2,'SINGLE_CHOICE'),(28,'2025-12-26 22:15:04.627825','2025-12-26 22:15:04.627844','Thế nào là Constructor mặc định (Default Constructor)?',8,1,NULL,_binary '\0',_binary '\0',_binary '\0',2,'SINGLE_CHOICE'),(29,'2025-12-26 22:15:04.663847','2025-12-26 22:15:04.663865','Tại sao ta cần sử dụng Getter/Setter thay vì truy cập trực tiếp các thuộc tính Private?',8,1,NULL,_binary '\0',_binary '\0',_binary '\0',2,'SINGLE_CHOICE'),(30,'2025-12-26 22:15:04.695498','2025-12-26 22:15:04.695515','Overloading Constructor (nạp chồng Constructor) là gì?',8,1,NULL,_binary '\0',_binary '\0',_binary '\0',2,'SINGLE_CHOICE'),(31,'2025-12-26 22:15:04.731827','2025-12-26 22:15:04.731847','Trong Java/C\\#, từ khóa `this()` bên trong một Constructor dùng để làm gì?',8,2,NULL,_binary '\0',_binary '\0',_binary '\0',2,'SINGLE_CHOICE'),(32,'2025-12-26 22:15:04.771203','2025-12-26 22:15:04.771221','Lợi ích chính của tính Đóng gói trong bảo mật dữ liệu là gì?',8,2,NULL,_binary '\0',_binary '\0',_binary '\0',2,'SINGLE_CHOICE'),(33,'2025-12-26 22:15:04.807509','2025-12-26 22:15:04.807528','Khi một Class KHÔNG khai báo bất kỳ Constructor nào, điều gì xảy ra?',8,2,NULL,_binary '\0',_binary '\0',_binary '\0',2,'SINGLE_CHOICE'),(34,'2025-12-26 22:15:04.840201','2025-12-26 22:15:04.840216','Nếu một Class chỉ có Constructor có tham số, ta có thể tạo Object mà không truyền tham số không?',8,2,NULL,_binary '\0',_binary '\0',_binary '\0',2,'SINGLE_CHOICE'),(35,'2025-12-26 22:15:04.868203','2025-12-26 22:15:04.868222','Trong thiết kế đối tượng, việc áp dụng Đóng gói giúp tuân thủ nguyên tắc SOLID nào nhiều nhất?',8,2,NULL,_binary '\0',_binary '\0',_binary '\0',2,'SINGLE_CHOICE'),(36,'2025-12-26 22:15:04.896912','2025-12-26 22:15:04.896928','Phân tích tại sao việc cho phép Getter trả về tham chiếu đến một đối tượng Private (Mutable Object) là một rủi ro Đóng gói (Encapsulation Leak).',8,3,NULL,_binary '\0',_binary '\0',_binary '\0',2,'SINGLE_CHOICE'),(37,'2025-12-26 22:15:04.931638','2025-12-26 22:15:04.931659','Giả sử Class `A` có thuộc tính `private final int value;`. Tại sao không cần phương thức Setter cho thuộc tính này?',8,3,NULL,_binary '\0',_binary '\0',_binary '\0',2,'SINGLE_CHOICE'),(38,'2025-12-26 22:15:04.966305','2025-12-26 22:15:04.966323','Trong một số framework, việc sử dụng Design Pattern nào để tạo Object phức tạp thay vì dùng trực tiếp Constructor là phổ biến?',8,3,NULL,_binary '\0',_binary '\0',_binary '\0',2,'SINGLE_CHOICE'),(39,'2025-12-26 22:15:04.999021','2025-12-26 22:15:04.999037','Để đảm bảo tính bất biến (Immutability) của một đối tượng, các yếu tố nào là cần thiết?',8,3,NULL,_binary '\0',_binary '\0',_binary '\0',2,'SINGLE_CHOICE'),(40,'2025-12-26 22:15:05.031273','2025-12-26 22:15:05.031291','So